summary:
Function: /* Single Producer / Single Consumer Ring Buffer for POD Types
 *
 * Implements a lock-free ring buffer for a single producer thread and
 * single consumer thread, suitable for passing POD types between two
 * threads without locks.
 *
 * The ring buffer is entirely lock-free for both producer and consumer
 * (uses atomics for synchronization).
 *
 * Producer and consumer must be separate threads. Behavior is undefined
 * if both try to produce or both try to consume.
 *
 * Not thread-safe for multiple producers or multiple consumers.
 *
 * The buffer size is fixed at creation time and must be a power of 2.
 */

#ifndef RING_BUFFER_H
#define RING_BUFFER_H

#include <stdbool.h>
#include <stddef.h>
#include <stdint.h>

typedef struct ring_buffer ring_buffer_t;

ring_buffer_t* ring_buffer_create(size_t num_items, size_t item_size);

void ring_buffer_destroy(ring_buffer_t* rb);

/* Producer API */

/* Producer calls this to get a pointer to the next item slot to write to.
 * Caller MUST check ring_buffer_producer_full() first, else behavior is
 * undefined.
 *
 * Sets *out_ptr to point to the next empty slot.
 *
 * Ordering: Uses acquire semantics to sync with consumer.
 */
void ring_buffer_producer_acquire(ring_buffer_t* rb, void** out_ptr);

/* Producer calls this after writing to the slot acquired via
 * ring_buffer_producer_acquire.
 * 
 * Ordering: Uses release semantics to publish item to consumer.
 */
void ring_buffer_producer_release(ring_buffer_t* rb);

/* Returns true if the ring buffer is full (no space for producer to write). */
bool ring_buffer_producer_full(const ring_buffer_t* rb);

/* Consumer API */

/* Consumer calls this to get a pointer to the next item slot to read from.
 * Caller MUST check ring_buffer_consumer_empty() first, else behavior is
 * undefined.
 *
 * Sets *out_ptr to point to the next full slot.
 *
 * Ordering: Uses acquire semantics to sync with producer.
 */
void ring_buffer_consumer_acquire(ring_buffer_t* rb, void** out_ptr);

/* Consumer calls this after reading from the slot acquired via
 * ring_buffer_consumer_acquire.
 * 
 * Ordering: Uses release semantics to publish slot back to producer.
 */
void ring_buffer_consumer_release(ring_buffer_t* rb);

/* Returns true if the ring buffer is empty (no items for consumer to read). */
bool ring_buffer_consumer_empty(const ring_buffer_t* rb);

#endif /* RING_BUFFER_H */
